function autoTranslate() {

  const subtitle = document.querySelector('.well--container--2edq4 span');
  const translate = document.querySelector('p[data-purpose="transcript-cue-active"] span');

  if(translate && subtitle && subtitle.innerText !== translate.innerText) {
    subtitle.innerText = translate.innerText;
  }
}

const s = setInterval(autoTranslate, 200);
